import SwiftUI
import Accessibility

struct AccessibleChartView: View {
    let data: [Double] = [10, 20, 15, 30, 25, 40]
    var body: some View {
        VStack {
            Chart(data) { value in
                BarMark(x: .value("Index", data.firstIndex(of: value) ?? 0), y: .value("Value", value))
            }
            .accessibilityAudioGraph(data)
            .accessibilityLabel("Sales Data")
            .accessibilityHint("Swipe up or down to hear data points.")
        }
    }
}

import SwiftUI

struct ErrorFormView: View {
    @State private var errors: [String] = ["Email is invalid", "Password too short"]
    var body: some View {
        Form {
            TextField("Email", text: .constant(""))
            SecureField("Password", text: .constant(""))
            ForEach(errors, id: \.self) { error in
                Text(error).foregroundColor(.red)
            }
        }
        .accessibilityRotor("Errors", entries: errors.map { error in
            AccessibilityRotorEntry(error, id: error)
        })
    }
}

