    }
}

import SwiftUI

struct AccessibleStepper: View {
    @State private var value: Int = 0
    var body: some View {
        HStack {
            Button("-") { value -= 1 }
            Text("Value: \(value)")
            Button("+") { value += 1 }
        }
        .accessibilityElement(children: .combine)
        .accessibilityValue("Current value is \(value)")
        .accessibilityAdjustableAction { direction in
            switch direction {
            case .increment: value += 1
            case .decrement: value -= 1
            default: break
            }
        }
    }
}

import SwiftUI

struct AccessibleBarChart: View {
    let data: [Double] = [5, 10, 7, 12]
    var body: some View {
        HStack {
            ForEach(data.indices, id: \.self) { i in
                Rectangle()
                    .frame(width: 20, height: data[i] * 10)
                    .accessibilityLabel("Bar \(i + 1)")
                    .accessibilityValue("Value: \(data[i])")
                    .accessibilityHint("Represents data point \(i + 1)")
            }
        }
        .accessibilityElement(children: .contain)
        .accessibilityLabel("Bar Chart")
    }
}

import SwiftUI

struct FavoriteListView: View {
    @State private var items = ["Apple", "Banana", "Cherry"]
    @State private var favorites: Set<String> = []
    var body: some View {
        List(items, id: \.self) { item in
            HStack {
                Text(item)
                if favorites.contains(item) {
                    Image(systemName: "star.fill").foregroundColor(.yellow)
                }
            }
            .accessibilityAddTraits(favorites.contains(item) ? .isSelected : [])
            .accessibilityAction(named: "Favorite") {
                if favorites.contains(item) { favorites.remove(item) }
                else { favorites.insert(item) }
            }
        }
    }
}

import SwiftUI

struct FocusedErrorView: View {
    @State private var showError = false
    @AccessibilityFocusState private var errorFocused: Bool
    var body: some View {
        VStack {
            Button("Submit") { showError = true; errorFocused = true }
            if showError {
                Text("Submission failed.")
                    .foregroundColor(.red)
                    .accessibilityFocused($errorFocused)
            }
        }
    }
}

